import React, { useEffect, useRef, useState } from 'react'
import classNames from 'classnames'
import styles from './toast.module.less'

export interface ToastProps {
  /** 通知文字 */
  message: string
  /** 是否显示 */
  visible?: boolean
  /** 自动关闭时间（ms），0 表示不自动关闭 */
  duration?: number
  /** 关闭回调 */
  onClose?: () => void
  /** 自定义类名 */
  className?: string
  /** 自定义样式 */
  style?: React.CSSProperties
}

const Toast: React.FC<ToastProps> = ({ message, visible = true, duration = 3000, onClose, className, style }) => {
  const [show, setShow] = useState(visible)

  // 用 ref 收住 onClose：避免父组件每次渲染传入新的内联函数时，
  // 把自动关闭的 timer 反复清除重建，导致 Toast 永不消失。
  const onCloseRef = useRef(onClose)
  useEffect(() => { onCloseRef.current = onClose }, [onClose])

  useEffect(() => { setShow(visible) }, [visible])

  useEffect(() => {
    if (show && duration > 0) {
      const timer = setTimeout(() => { setShow(false); onCloseRef.current?.() }, duration)
      return () => clearTimeout(timer)
    }
  }, [show, duration])

  if (!show) return null

  return (
    <div className={classNames(styles.container, className)} style={style} role="alert" aria-live="polite">
      <div className={styles.innerBorder} />
      <span className={styles.message}>{message}</span>
    </div>
  )
}

Toast.displayName = 'Toast'
export default Toast

import React from 'react'
import classNames from 'classnames'
import styles from './healthBar.module.less'

export interface HealthBarProps {
  /** 当前生命值 */
  current: number
  /** 最大生命值 */
  max: number
  /** 奖励心心数量 */
  bonus?: number
  /** 自定义类名 */
  className?: string
  /** 自定义样式 */
  style?: React.CSSProperties
}

/** 从 Figma 导出的精确心形路径 */
const HEART_PATH = "M21.7675 12.7969L12.1037 21.7487L2.05872 11.598C-0.686241 8.82416 -0.686239 4.35741 2.05872 1.58356C4.14815 -0.527857 7.55918 -0.527854 9.64861 1.58357L12.1037 4.06447L14.0676 2.0798C16.3794 -0.256337 20.1909 -0.129535 22.3423 2.35509C24.9973 5.42139 24.7431 10.0406 21.7675 12.7969Z"

const HeartIcon: React.FC<{ type: 'filled' | 'empty' | 'bonus' }> = ({ type }) => {
  const fill = type === 'filled' ? '#F1362F' : type === 'bonus' ? '#FFE465' : '#363930'

  return (
    <svg aria-hidden="true" width="30" height="24" viewBox="0 0 24.18 21.75" fill="none" xmlns="http://www.w3.org/2000/svg">
      <path d={HEART_PATH} fill={fill} />
    </svg>
  )
}

const HealthBar: React.FC<HealthBarProps> = ({
  current,
  max,
  bonus = 0,
  className,
  style,
}) => {
  const hearts = []

  for (let i = 0; i < max; i++) {
    const filled = i < current
    hearts.push(
      <span key={`heart-${i}`} className={classNames(styles.heart, {
        [styles.filled]: filled,
        [styles.empty]: !filled,
      })}>
        <HeartIcon type={filled ? 'filled' : 'empty'} />
      </span>
    )
  }

  for (let i = 0; i < bonus; i++) {
    hearts.push(
      <span key={`bonus-${i}`} className={classNames(styles.heart, styles.bonus)}>
        <HeartIcon type="bonus" />
      </span>
    )
  }

  return (
    <div className={classNames(styles.container, className)} style={style}>
      {hearts}
    </div>
  )
}

HealthBar.displayName = 'HealthBar'
export default HealthBar

import React from 'react'
import classNames from 'classnames'
import styles from './divineBeast.module.less'
import beastRutaSvg from '@core/assets/svg/beast-ruta.svg'
import beastMedohSvg from '@core/assets/svg/beast-medoh.svg'
import beastNaborisSvg from '@core/assets/svg/beast-naboris.svg'
import beastRudaniaSvg from '@core/assets/svg/beast-rudania.svg'

export type BeastType = 'ruta' | 'medoh' | 'naboris' | 'rudania'

export interface DivineBeastProps {
  /** 神兽类型 */
  beast: BeastType
  /** 是否充能中 */
  recharging?: boolean
  /** 可用次数 */
  charges?: number
  /** 尺寸（默认 75px） */
  size?: number
  /** 自定义类名 */
  className?: string
  /** 自定义样式 */
  style?: React.CSSProperties
}

const BEAST_SVGS: Record<BeastType, string> = {
  ruta: beastRutaSvg,
  medoh: beastMedohSvg,
  naboris: beastNaborisSvg,
  rudania: beastRudaniaSvg,
}

/** 精确还原 Figma 中的神兽辉光色 */
const BEAST_SHADOWS: Record<BeastType, string> = {
  ruta: '0 0 4px #27CBFF, 0 0 5px #27CBFF, 0 0 15px #27CBFF',
  medoh: '0 0 4px #7CFF4E, 0 0 5px #7CFF4E, 0 0 15px #7CFF4E',
  naboris: '0 0 4px #FCC63D, 0 0 5px #F8AF42, 0 0 15px #BD8B28',
  rudania: '0 0 4px #EB4713, 0 0 5px #EB4815, 0 0 15px #EC4916',
}

const DivineBeast: React.FC<DivineBeastProps> = ({
  beast,
  recharging = false,
  charges = 1,
  size = 75,
  className,
  style,
}) => {
  const shadow = recharging
    ? '0 0 4px #FF0000, 0 0 5px #FF0000, 0 0 15px #FF0000'
    : BEAST_SHADOWS[beast]

  return (
    <div
      className={classNames(styles.container, { [styles.recharging]: recharging }, className)}
      style={{ width: size, height: size, boxShadow: shadow, ...style }}
    >
      <img src={BEAST_SVGS[beast]} alt="" className={styles.icon} />
      {charges > 0 && (
        <span className={styles.charges}>
          <span className={styles.times}>×</span>
          <span className={styles.count}>{charges}</span>
        </span>
      )}
    </div>
  )
}

DivineBeast.displayName = 'DivineBeast'
export default DivineBeast

